const text = String(query || '').toLowerCase();
const urgent = /(broken|damaged|refund|lawyer|lawsuit|police|unacceptable|money back|??????|???????|??????? ??????|???|?????|???????|??????|?????)/.test(text);
const human = /(human|manager|operator|agent|????????|????????|???????)/.test(text);
const refund = /(refund|return|money back|???????|???????|??????? ??????)/.test(text);
return JSON.stringify({ urgent, human_review_required: urgent || human || refund, reason: urgent ? 'urgent_or_complaint_terms' : human ? 'human_requested' : refund ? 'refund_or_return_judgment' : 'standard_review' });
